fn main() {
    let stdin = std::io::stdin();
    let lock = stdin.lock();
    let mut r = io::Reader::new(lock);
    let mut w = io::Writer::new();

    let l = ['c', 'o', 'd', 'e', 'f', 'o', 'r', 'c', 'e', 's'];
    let mut v = vec![1u64; 10];
    let mut max_comb = 1u64;
    let mut selection = 0usize;
    let n: u64 = r.read()[0];

    while max_comb < n {
        for i in 0..v.len() {
            let comb = compute(&v, i);
            if comb > max_comb {
                selection = i;
                max_comb = comb;
            }
        }
        v[selection] += 1;
    }

    for i in 0..v.len() {
        for _ in 0..v[i] {
            w.push(l[i]);
        }
    }
    w.push('\n');

    w.write();
}

fn compute(v: &Vec<u64>, i: usize) -> u64 {
    let mut comb = 1;
    for j in 0..v.len() {
        comb *= if j == i { v[j] + 1 } else { v[j] }
    }

    comb
}

pub mod io {
    use std::fmt::{Debug, Display};
    use std::io::{BufRead, StdinLock};
    use std::str::FromStr;

    pub struct Reader<'a> {
        buffer: String,
        lock: StdinLock<'a>,
    }

    impl<'a> Reader<'a> {
        pub fn new(lock: StdinLock<'a>) -> Self {
            Reader {
                buffer: String::with_capacity(4 * 1024 * 1024),
                lock,
            }
        }

        pub fn read<T>(&mut self) -> Vec<T>
        where
            T: Copy + FromStr + Display,
            <T as FromStr>::Err: Debug,
        {
            self.buffer.clear();

            self.lock
                .read_line(&mut self.buffer)
                .expect("Failed to get input");

            self.buffer
                .trim()
                .split_whitespace()
                .map(|x| x.parse().expect("Failed to parse value"))
                .collect()
        }
    }

    pub struct Writer {
        buffer: String,
    }

    impl Writer {
        pub fn new() -> Self {
            Writer {
                buffer: String::with_capacity(4 * 1024 * 1024),
            }
        }

        pub fn push<T: Display>(&mut self, data: T) {
            self.buffer.push_str(&format!("{}", data));
        }

        pub fn pushw<T: Display>(&mut self, data: T) {
            self.buffer.push_str(&format!("{} ", data));
        }

        pub fn pushln<T: Display>(&mut self, data: T) {
            self.buffer.push_str(&format!("{}\n", data));
        }

        pub fn write(&self) {
            print!("{}", self.buffer);
        }
    }
}
